// src/app/api/spaces/[spaceId]/invites/route.ts
import { NextResponse } from 'next/server'
import prisma from '@/lib/db'
import { getAuthenticatedUserId, unauthorizedResponse } from '@/lib/auth-utils'
import { validateSpaceAccess, SpacePermissions } from '@/lib/space-context'
import { randomBytes } from 'crypto'

export async function GET(
  request: Request,
  { params }: { params: Promise<{ spaceId: string }> }
) {
  try {
    const userId = await getAuthenticatedUserId()
    const { spaceId } = await params
    const membership = await validateSpaceAccess(userId, spaceId)
    const perms = new SpacePermissions(membership.role)

    if (!perms.canManageSpace()) {
      return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
    }

    const invites = await prisma.spaceInvite.findMany({
      where: { spaceId, status: 'PENDING' },
      orderBy: { createdAt: 'desc' },
    })

    return NextResponse.json(invites)
  } catch (error) {
    if (error instanceof Error && error.message === 'Unauthorized') {
      return unauthorizedResponse()
    }
    if (error instanceof Error && error.message === 'Forbidden') {
      return NextResponse.json({ error: 'Sem acesso ao espaço' }, { status: 403 })
    }
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

export async function POST(
  request: Request,
  { params }: { params: Promise<{ spaceId: string }> }
) {
  try {
    const userId = await getAuthenticatedUserId()
    const { spaceId } = await params
    const membership = await validateSpaceAccess(userId, spaceId)
    const perms = new SpacePermissions(membership.role)

    if (!perms.canManageSpace()) {
      return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
    }

    const body = await request.json()
    const { email, role } = body

    if (!role || !['ADMIN', 'MEMBER', 'LIMITED'].includes(role)) {
      return NextResponse.json({ error: 'Role inválido' }, { status: 400 })
    }

    const code = randomBytes(16).toString('hex')
    const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000) // 7 days

    const invite = await prisma.spaceInvite.create({
      data: {
        spaceId,
        email: email?.toLowerCase() || null,
        code,
        role,
        expiresAt,
      },
    })

    return NextResponse.json(invite, { status: 201 })
  } catch (error) {
    if (error instanceof Error && error.message === 'Unauthorized') {
      return unauthorizedResponse()
    }
    if (error instanceof Error && error.message === 'Forbidden') {
      return NextResponse.json({ error: 'Sem acesso ao espaço' }, { status: 403 })
    }
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

'use client'

import { useState, useEffect } from 'react'

type Permissions = {
  canViewTransactions: boolean
  canEditTransactions: boolean
  canViewAllTransactions: boolean
  canViewInvestments: boolean
  canViewBudgets: boolean
  canManageSpace: boolean
  canViewIncomes: boolean
  isSpaceContext: boolean
  role: string | null
}

export function useSpacePermissions(): Permissions & { loading: boolean } {
  const [permissions, setPermissions] = useState<Permissions>({
    canViewTransactions: true,
    canEditTransactions: true,
    canViewAllTransactions: true,
    canViewInvestments: true,
    canViewBudgets: true,
    canManageSpace: false,
    canViewIncomes: true,
    isSpaceContext: false,
    role: null,
  })
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetch('/api/spaces/active/permissions')
      .then((res) => res.json())
      .then(setPermissions)
      .catch(() => {
        // Keep default permissions on error
      })
      .finally(() => setLoading(false))
  }, [])

  return { ...permissions, loading }
}

