 18→    const search = searchParams.get("search");
 19→    const tag = searchParams.get("tag");
 20→    const includeDeleted = searchParams.get("includeDeleted");
 21→
 22→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
 23→    const where: Record<string, any> = {
 24→      ...ctx.ownerFilter,
 25→    };
 26→
 27→    // By default, exclude soft-deleted transactions
 28→    if (includeDeleted !== "true") {
 29→      where.deletedAt = null;
 30→    }
 31→
 32→    // Custom date range filter takes priority
 33→    if (startDate && endDate) {
 34→      where.date = {
 35→        gte: new Date(startDate),
 36→        lte: new Date(endDate),
 37→      };
 38→    } else if (month && year) {
 39→      const monthStart = new Date(parseInt(year), parseInt(month) - 1, 1);
 40→      const monthEnd = new Date(parseInt(year), parseInt(month), 0);
 41→      where.date = {
 42→        gte: monthStart,
 43→        lte: monthEnd,
 44→      };
 45→    } else if (year) {
 46→      const yearStart = new Date(parseInt(year), 0, 1);
 47→      const yearEnd = new Date(parseInt(year), 11, 31);
 48→      where.date = {
 49→        gte: yearStart,
 50→        lte: yearEnd,
 51→      };
 52→    }
 53→
 54→    // Global text search
 55→    if (search && search.trim()) {
 56→      where.description = {
 57→        contains: search.trim(),
 58→      };
 59→    }
 60→
 61→    if (categoryId) {
 62→      where.categoryId = categoryId;
 63→    }
 64→
 65→    if (origin) {
 66→      where.origin = origin;
 67→    }
 68→
 69→    if (type) {
 70→      where.type = type;
 71→    }
 72→
 73→    if (isFixed === "true") {
 74→      where.isFixed = true;
 75→    }
 76→
 77→    if (isInstallment === "true") {
 78→      where.isInstallment = true;
 79→    }
 80→
 81→    // Filter standalone installments (not linked to an Installment group)
 82→    const standalone = searchParams.get("standalone");
 83→    if (standalone === "true") {
 84→      where.installmentId = null;
 85→    }
 86→
 87→    // Filter by tag (searches within JSON array string)
 88→    if (tag && tag.trim()) {
 89→      where.tags = {
 90→        contains: tag.trim(),
 91→      };
 92→    }
 93→
 94→    // In space context with LIMITED role, only show own transactions
 95→    if (ctx.spaceId && ctx.permissions && !ctx.permissions.canViewAllTransactions()) {
 96→      where.createdByUserId = ctx.userId;
 97→    }
 98→
 99→    // In space context, also include personal non-private transactions from members
100→    if (ctx.spaceId) {
101→      const memberIds = await prisma.spaceMember.findMany({
102→        where: { spaceId: ctx.spaceId },
103→        select: { userId: true },
104→      });
105→      const memberUserIds = memberIds.map(m => m.userId);
106→
107→      // Extract non-ownership filters to apply to both branches of OR
108→      const { spaceId: _spaceId, createdByUserId, ...otherFilters } = where;
109→
110→      // Build OR condition for space context
111→      const orConditions: Record<string, unknown>[] = [
112→        { spaceId: ctx.spaceId }, // direct space transactions
113→        {
114→          userId: { in: memberUserIds },
115→          spaceId: null,
116→          isPrivate: false,
117→        }, // personal non-private from members
118→      ];
119→
120→      // If LIMITED role, further restrict the OR conditions
121→      if (createdByUserId) {
122→        orConditions[0] = { ...orConditions[0], createdByUserId };
123→        orConditions[1] = { ...orConditions[1], userId: createdByUserId };
124→      }
125→
126→      // Reconstruct where with OR
127→      const newWhere: Record<string, unknown> = {
128→        OR: orConditions,
129→        ...otherFilters,
130→      };
131→
132→      const transactions = await prisma.transaction.findMany({
133→        where: newWhere,
134→        include: {
135→          category: true,
136→          categoryTag: true,
137→          installment: true,
138→        },
139→        orderBy: {
140→          date: "desc",
141→        },
142→      });
143→
144→      return NextResponse.json(transactions);
145→    }
146→
147→    const transactions = await prisma.transaction.findMany({
148→      where,
149→      include: {
150→        category: true,
151→        categoryTag: true,
152→        installment: true,
153→      },
154→      orderBy: {
155→        date: "desc",
156→      },
157→    });
