141→export async function DELETE(
142→  request: NextRequest,
143→  { params }: { params: Promise<{ id: string }> }
144→) {
145→  try {
146→    const ctx = await getAuthContext();
147→    const { id } = await params;
148→    const searchParams = request.nextUrl.searchParams;
149→    const permanent = searchParams.get("permanent");
150→
151→    // Verify transaction belongs to user/space before deleting
152→    const existingTransaction = await prisma.transaction.findFirst({
153→      where: { id, ...ctx.ownerFilter },
154→    });
155→
156→    if (!existingTransaction) {
157→      return NextResponse.json(
158→        { error: "Transacao nao encontrada" },
159→        { status: 404 }
160→      );
161→    }
162→
163→    // In space context with LIMITED role, only allow deleting own transactions
164→    if (ctx.spaceId && ctx.permissions && !ctx.permissions.canViewAllTransactions()) {
165→      if (existingTransaction.createdByUserId !== ctx.userId) {
166→        return NextResponse.json({ error: 'Sem permissão' }, { status: 403 });
167→      }
168→    }
169→
170→    // Personal transactions mirrored in space can only be mutated by the owner
171→    if (!existingTransaction.spaceId && existingTransaction.userId !== ctx.userId) {
172→      return NextResponse.json({ error: 'Sem permissão' }, { status: 403 });
173→    }
174→
175→    if (permanent === "true") {
176→      // Permanent delete
177→      await prisma.transaction.delete({
178→        where: { id },
179→      });
180→    } else {
181→      // Soft delete - set deletedAt timestamp
182→      await prisma.transaction.update({
183→        where: { id },
184→        data: { deletedAt: new Date() },
185→      });
186→    }
187→
188→    return NextResponse.json({ success: true });
189→  } catch (error) {
190→    if (error instanceof Error && error.message === "Unauthorized") {
191→      return unauthorizedResponse();
192→    }
193→    if (error instanceof Error && error.message === "Forbidden") {
194→      return forbiddenResponse();
195→    }
196→    console.error("Error deleting transaction:", error);
197→    return NextResponse.json(
198→      { error: "Erro ao excluir transacao" },
199→      { status: 500 }
200→    );
201→  }
202→}
