**useSpacePermissions hook:**
```typescript
export function useSpacePermissions(): Permissions & { loading: boolean } {
  const [permissions, setPermissions] = useState<Permissions>({...defaults})
  const [loading, setLoading] = useState(true)
  useEffect(() => {
    fetch('/api/spaces/active/permissions')
      .then((res) => res.json())
      .then(setPermissions)
      .catch(() => { /* Keep default permissions on error */ })
      .finally(() => setLoading(false))
  }, [])
