 7→export async function PATCH(
 8→  request: Request,
 9→  { params }: { params: Promise<{ spaceId: string; memberId: string }> }
10→) {
11→  try {
12→    const userId = await getAuthenticatedUserId()
13→    const { spaceId, memberId } = await params
14→    const membership = await validateSpaceAccess(userId, spaceId)
15→    const perms = new SpacePermissions(membership.role)
16→
17→    if (!perms.canManageSpace()) {
18→      return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
