175→export async function POST(request: NextRequest) {
176→  try {
177→    const ctx = await getAuthContext();
178→    const body = await request.json();
179→    const {
180→      description,
181→      amount,
182→      date,
183→      type,
184→      origin,
185→      categoryId,
186→      isFixed,
187→      isInstallment,
188→      totalInstallments,
189→      installmentAmount,
190→      tags,
191→    } = body;
192→
193→    // Process tags - accept array or string, store as JSON string
194→    const processedTags = tags
195→      ? Array.isArray(tags)
196→        ? JSON.stringify(tags)
197→        : tags
198→      : null;
199→
200→    if (isInstallment && totalInstallments > 1) {
201→      // Create installment group and transactions
202→      const installment = await prisma.installment.create({
203→        data: {
204→          description,
205→          totalAmount: Math.abs(amount) * totalInstallments,
206→          totalInstallments,
207→          installmentAmount: installmentAmount || Math.abs(amount),
208→          startDate: new Date(date + "T12:00:00"),
209→          origin,
210→          userId: ctx.userId,
211→          spaceId: ctx.spaceId,
212→        },
213→      });
214→
215→      const transactions = [];
216→      const startDate = new Date(date + "T12:00:00");
217→
218→      for (let i = 0; i < totalInstallments; i++) {
219→        const transactionDate = new Date(startDate);
220→        transactionDate.setMonth(transactionDate.getMonth() + i);
221→
222→        const transaction = await prisma.transaction.create({
223→          data: {
224→            description: `${description} (${i + 1}/${totalInstallments})`,
225→            amount: type === "EXPENSE" ? -Math.abs(installmentAmount || amount) : Math.abs(installmentAmount || amount),
226→            date: transactionDate,
227→            type,
228→            origin,
229→            categoryId: categoryId || null,
230→            isFixed: false,
231→            isInstallment: true,
232→            installmentId: installment.id,
233→            currentInstallment: i + 1,
234→            tags: processedTags,
235→            userId: ctx.userId,
236→            spaceId: ctx.spaceId,
237→            createdByUserId: ctx.userId,
238→          },
239→          include: {
240→            category: true,
241→            installment: true,
242→          },
243→        });
244→        transactions.push(transaction);
245→      }
246→
247→      return NextResponse.json(transactions[0], { status: 201 });
248→    } else {
249→      const transaction = await prisma.transaction.create({
250→        data: {
251→          description,
252→          amount: type === "EXPENSE" ? -Math.abs(amount) : Math.abs(amount),
253→          date: new Date(date + "T12:00:00"),
254→          type,
255→          origin,
256→          categoryId: categoryId || null,
257→          isFixed: isFixed || false,
258→          isInstallment: false,
259→          tags: processedTags,
260→          userId: ctx.userId,
261→          spaceId: ctx.spaceId,
262→          createdByUserId: ctx.userId,
263→        },
264→        include: {
265→          category: true,
266→        },
267→      });
268→
269→      return NextResponse.json(transaction, { status: 201 });
270→    }
271→  } catch (error) {
272→    if (error instanceof Error && error.message === "Unauthorized") {
273→      return unauthorizedResponse();
274→    }
275→    if (error instanceof Error && error.message === "Forbidden") {
276→      return forbiddenResponse();
277→    }
278→    console.error("Error creating transaction:", error);
279→    return NextResponse.json(
280→      { error: "Erro ao criar transacao" },
281→      { status: 500 }
282→    );
283→  }
284→}
