 51→export async function PUT(
 52→  request: NextRequest,
 53→  { params }: { params: Promise<{ id: string }> }
 54→) {
 55→  try {
 56→    const ctx = await getAuthContext();
 57→    const { id } = await params;
 58→    const body = await request.json();
 59→    const {
 60→      description,
 61→      amount,
 62→      date,
 63→      type,
 64→      origin,
 65→      categoryId,
 66→      isFixed,
 67→      tags,
 68→      isInstallment,
 69→      currentInstallment,
 70→      totalInstallments,
 71→    } = body;
 72→
 73→    // Process tags - accept array or string, store as JSON string
 74→    const processedTags = tags
 75→      ? Array.isArray(tags)
 76→        ? JSON.stringify(tags)
 77→        : tags
 78→      : null;
 79→
 80→    // Verify transaction belongs to user/space before updating
 81→    const existingTransaction = await prisma.transaction.findFirst({
 82→      where: { id, ...ctx.ownerFilter },
 83→    });
 84→
 85→    if (!existingTransaction) {
 86→      return NextResponse.json(
 87→        { error: "Transacao nao encontrada" },
 88→        { status: 404 }
 89→      );
 90→    }
 91→
 92→    // In space context with LIMITED role, only allow editing own transactions
 93→    if (ctx.spaceId && ctx.permissions && !ctx.permissions.canViewAllTransactions()) {
 94→      if (existingTransaction.createdByUserId !== ctx.userId) {
 95→        return NextResponse.json({ error: 'Sem permissão' }, { status: 403 });
 96→      }
 97→    }
 98→
 99→    // Personal transactions mirrored in space can only be mutated by the owner
100→    if (!existingTransaction.spaceId && existingTransaction.userId !== ctx.userId) {
