 28→export async function POST(request: Request) {
 29→  try {
 30→    const userId = await getAuthenticatedUserId()
 31→    const body = await request.json()
 32→    const { name } = body
 33→
 34→    if (!name || typeof name !== 'string' || name.trim().length === 0) {
 35→      return NextResponse.json({ error: 'Nome é obrigatório' }, { status: 400 })
 36→    }
 37→
 38→    // Create space with creator as ADMIN
 39→    const space = await prisma.space.create({
