 48→    })
 49→
 50→    // Copy user's categories, origins, rules, investment categories to space
 51→    await copyUserDataToSpace(userId, space.id)
 52→
 53→    return NextResponse.json(space, { status: 201 })
 54→  } catch (error) {
 55→    if (error instanceof Error && error.message === 'Unauthorized') {
