"use client";

import { useEffect, useState } from "react";
import { Mail, Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogTrigger,
} from "@/components/ui/dialog";
import { useToast } from "@/components/ui/use-toast";

interface PendingInvite {
  id: string;
  code: string;
  space: {
    id: string;
    name: string;
  };
}

export function PendingInvites() {
  const [invites, setInvites] = useState<PendingInvite[]>([]);
  const [open, setOpen] = useState(false);
  const [accepting, setAccepting] = useState<string | null>(null);
  const { toast } = useToast();

  useEffect(() => {
    fetch("/api/invites/pending")
      .then((res) => res.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setInvites(data);
        }
      })
      .catch(() => {});
  }, []);

  async function handleAccept(invite: PendingInvite) {
    setAccepting(invite.id);
    try {
      const res = await fetch(`/api/invites/${invite.code}/accept`, {
        method: "POST",
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || "Erro ao aceitar convite");
      }

      setInvites((prev) => prev.filter((i) => i.id !== invite.id));
      toast({
        title: "Convite aceito",
        description: `Você agora faz parte do espaço "${invite.space.name}"`,
      });

      // Close dialog if no more invites
      if (invites.length <= 1) {
        setOpen(false);
      }
    } catch (error) {
      toast({
        title: "Erro",
        description:
          error instanceof Error ? error.message : "Erro ao aceitar convite",
        variant: "destructive",
      });
    } finally {
      setAccepting(null);
    }
  }

  if (invites.length === 0) {
    return null;
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <button
          className="flex w-full items-center gap-3 rounded-lg px-3 py-2 text-sm font-medium text-emerald-700 bg-emerald-50 transition-colors hover:bg-emerald-100"
          aria-label={`${invites.length} convite${invites.length > 1 ? "s" : ""} pendente${invites.length > 1 ? "s" : ""}`}
        >
          <Mail className="h-5 w-5" />
          <span className="flex-1 text-left">Convites</span>
          <span className="flex h-5 w-5 items-center justify-center rounded-full bg-emerald-600 text-xs font-bold text-white">
            {invites.length}
          </span>
        </button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Convites pendentes</DialogTitle>
          <DialogDescription>
            Você tem {invites.length} convite{invites.length > 1 ? "s" : ""}{" "}
            para espaços compartilhados.
          </DialogDescription>
        </DialogHeader>
        <div className="space-y-3">
          {invites.map((invite) => (
            <div
              key={invite.id}
              className="flex items-center justify-between rounded-lg border p-3"
            >
              <div>
                <p className="font-medium text-gray-900">
                  {invite.space.name}
                </p>
              </div>
              <Button
                size="sm"
                onClick={() => handleAccept(invite)}
                disabled={accepting === invite.id}
              >
                {accepting === invite.id ? (
                  "Aceitando..."
                ) : (
                  <>
                    <Check className="mr-1 h-4 w-4" />
                    Aceitar
                  </>
                )}
              </Button>
            </div>
          ))}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { renderHook, waitFor } from '@testing-library/react'
import { useSpacePermissions } from './useSpacePermissions'

// Mock global fetch
const mockFetch = vi.fn()
global.fetch = mockFetch

describe('useSpacePermissions', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  afterEach(() => {
    vi.restoreAllMocks()
  })

  it('returns loading true initially', () => {
    mockFetch.mockReturnValue(new Promise(() => {})) // never resolves
    const { result } = renderHook(() => useSpacePermissions())
    expect(result.current.loading).toBe(true)
  })

  it('returns default personal permissions when API returns personal context', async () => {
    const personalPermissions = {
      canViewTransactions: true,
      canEditTransactions: true,
      canViewAllTransactions: true,
      canViewInvestments: true,
      canViewBudgets: true,
      canManageSpace: false,
      canViewIncomes: true,
      isSpaceContext: false,
      role: null,
    }

    mockFetch.mockResolvedValue({
      json: () => Promise.resolve(personalPermissions),
    })

    const { result } = renderHook(() => useSpacePermissions())

    await waitFor(() => {
      expect(result.current.loading).toBe(false)
    })

    expect(result.current.canViewTransactions).toBe(true)
    expect(result.current.canEditTransactions).toBe(true)
    expect(result.current.canViewAllTransactions).toBe(true)
    expect(result.current.canViewInvestments).toBe(true)
    expect(result.current.canViewBudgets).toBe(true)
    expect(result.current.canManageSpace).toBe(false)
    expect(result.current.canViewIncomes).toBe(true)
    expect(result.current.isSpaceContext).toBe(false)
    expect(result.current.role).toBeNull()
  })

  it('returns space permissions when API returns space context', async () => {
    const spacePermissions = {
      canViewTransactions: true,
      canEditTransactions: true,
      canViewAllTransactions: false,
      canViewInvestments: false,
      canViewBudgets: false,
      canManageSpace: false,
      canViewIncomes: false,
      isSpaceContext: true,
      role: null,
    }

    mockFetch.mockResolvedValue({
      json: () => Promise.resolve(spacePermissions),
    })

    const { result } = renderHook(() => useSpacePermissions())

    await waitFor(() => {
      expect(result.current.loading).toBe(false)
    })

    expect(result.current.canViewInvestments).toBe(false)
    expect(result.current.canViewBudgets).toBe(false)
    expect(result.current.canManageSpace).toBe(false)
    expect(result.current.canViewIncomes).toBe(false)
    expect(result.current.isSpaceContext).toBe(true)
  })

  it('fetches from /api/spaces/active/permissions', async () => {
    mockFetch.mockResolvedValue({
      json: () => Promise.resolve({
        canViewTransactions: true,
        canEditTransactions: true,
        canViewAllTransactions: true,
        canViewInvestments: true,
        canViewBudgets: true,
        canManageSpace: false,
        canViewIncomes: true,
        isSpaceContext: false,
        role: null,
      }),
    })

    renderHook(() => useSpacePermissions())

    expect(mockFetch).toHaveBeenCalledWith('/api/spaces/active/permissions')
  })

  it('sets loading false even when fetch fails', async () => {
    mockFetch.mockRejectedValue(new Error('Network error'))

    const { result } = renderHook(() => useSpacePermissions())

    await waitFor(() => {
      expect(result.current.loading).toBe(false)
    })

    // Should keep default permissions on error
    expect(result.current.canViewTransactions).toBe(true)
    expect(result.current.isSpaceContext).toBe(false)
  })
})

// src/app/api/invites/pending/route.ts
import { NextResponse } from 'next/server'
import prisma from '@/lib/db'
import { getAuthenticatedUserId, unauthorizedResponse } from '@/lib/auth-utils'
import { auth } from '@/auth'

export async function GET() {
  try {
    const userId = await getAuthenticatedUserId()
    const session = await auth()
    const email = session?.user?.email

    if (!email) {
      return NextResponse.json([])
    }

    const invites = await prisma.spaceInvite.findMany({
      where: {
        email: email.toLowerCase(),
        status: 'PENDING',
        expiresAt: { gt: new Date() },
      },
      include: {
        space: { select: { id: true, name: true } },
      },
    })

    return NextResponse.json(invites)
  } catch (error) {
    if (error instanceof Error && error.message === 'Unauthorized') {
      return unauthorizedResponse()
    }
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

// src/app/api/spaces/[spaceId]/members/route.ts
import { NextResponse } from 'next/server'
import prisma from '@/lib/db'
import { getAuthenticatedUserId, unauthorizedResponse } from '@/lib/auth-utils'
import { validateSpaceAccess } from '@/lib/space-context'

export async function GET(
  request: Request,
  { params }: { params: Promise<{ spaceId: string }> }
) {
  try {
    const userId = await getAuthenticatedUserId()
    const { spaceId } = await params
    await validateSpaceAccess(userId, spaceId)

    const members = await prisma.spaceMember.findMany({
      where: { spaceId },
      include: {
        user: { select: { id: true, name: true, email: true, image: true } },
      },
    })

    return NextResponse.json(members)
  } catch (error) {
    if (error instanceof Error && error.message === 'Unauthorized') {
      return unauthorizedResponse()
    }
    if (error instanceof Error && error.message === 'Forbidden') {
      return NextResponse.json({ error: 'Sem acesso' }, { status: 403 })
    }
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

