// src/app/api/spaces/route.ts
import { NextResponse } from 'next/server'
import prisma from '@/lib/db'
import { getAuthenticatedUserId, unauthorizedResponse } from '@/lib/auth-utils'

export async function GET() {
  try {
    const userId = await getAuthenticatedUserId()

    const memberships = await prisma.spaceMember.findMany({
      where: { userId },
      include: {
        space: {
          select: { id: true, name: true, createdBy: true, createdAt: true },
        },
      },
    })

    return NextResponse.json(memberships)
  } catch (error) {
    if (error instanceof Error && error.message === 'Unauthorized') {
      return unauthorizedResponse()
    }
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

export async function POST(request: Request) {
  try {
    const userId = await getAuthenticatedUserId()
    const body = await request.json()
    const { name } = body

    if (!name || typeof name !== 'string' || name.trim().length === 0) {
      return NextResponse.json({ error: 'Nome é obrigatório' }, { status: 400 })
    }

    // Create space with creator as ADMIN
    const space = await prisma.space.create({
      data: {
        name: name.trim(),
        createdBy: userId,
        members: {
          create: { userId, role: 'ADMIN' },
        },
      },
      include: { members: true },
    })

    // Copy user's categories, origins, rules, investment categories to space
    await copyUserDataToSpace(userId, space.id)

    return NextResponse.json(space, { status: 201 })
  } catch (error) {
    if (error instanceof Error && error.message === 'Unauthorized') {
      return unauthorizedResponse()
    }
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

async function copyUserDataToSpace(userId: string, spaceId: string) {
  // Copy categories
  const categories = await prisma.category.findMany({
    where: { userId, spaceId: null },
  })
  if (categories.length > 0) {
    await prisma.category.createMany({
      data: categories.map((c) => ({
        name: c.name,
        color: c.color,
        icon: c.icon,
        userId,
        spaceId,
      })),
    })
  }

  // Copy origins
  const origins = await prisma.origin.findMany({
    where: { userId, spaceId: null },
  })
  if (origins.length > 0) {
    await prisma.origin.createMany({
      data: origins.map((o) => ({
        name: o.name,
        userId,
        spaceId,
      })),
    })
  }

  // Copy investment categories
  const investmentCategories = await prisma.investmentCategory.findMany({
    where: { userId, spaceId: null },
  })
  if (investmentCategories.length > 0) {
    await prisma.investmentCategory.createMany({
      data: investmentCategories.map((ic) => ({
        name: ic.name,
        icon: ic.icon,
        color: ic.color,
        userId,
        spaceId,
      })),
    })
  }

  // Copy category rules (need new category IDs)
  const spaceCategories = await prisma.category.findMany({
    where: { userId, spaceId },
  })
  const categoryNameToId = new Map(spaceCategories.map((c) => [c.name, c.id]))

  const rules = await prisma.categoryRule.findMany({
    where: { userId, spaceId: null },
    include: { category: true },
  })
  const rulesToCreate = rules
    .filter((r) => categoryNameToId.has(r.category.name))
    .map((r) => ({
      keyword: r.keyword,
      categoryId: categoryNameToId.get(r.category.name)!,
      userId,
      spaceId,
    }))
  if (rulesToCreate.length > 0) {
    await prisma.categoryRule.createMany({ data: rulesToCreate })
  }
}

import { auth } from "@/auth"
import { NextResponse } from "next/server"
import { getActiveSpaceId, validateSpaceAccess, SpacePermissions } from "./space-context"

/**
 * Gets the authenticated user's ID from the session.
 * This should be used in every API route to ensure data isolation.
 *
 * @throws Error if user is not authenticated
 */
export async function getAuthenticatedUserId(): Promise<string> {
  const session = await auth()

  if (!session?.user?.id) {
    throw new Error("Unauthorized")
  }

  return session.user.id
}

/**
 * Helper to create an unauthorized response.
 * Use this when catching authentication errors in API routes.
 */
export function unauthorizedResponse() {
  return NextResponse.json(
    { error: "Não autorizado. Faça login para continuar." },
    { status: 401 }
  )
}

/**
 * Helper to create a forbidden response.
 * Use this when catching authorization errors in API routes.
 */
export function forbiddenResponse() {
  return NextResponse.json({ error: "Forbidden" }, { status: 403 })
}

/**
 * Gets the session if available, returns null otherwise.
 * Use this for optional authentication checks.
 */
export async function getOptionalSession() {
  return await auth()
}

export type AuthContext = {
  userId: string
  spaceId: string | null
  permissions: SpacePermissions | null
  /** Para queries: userId se contexto pessoal, spaceId se contexto espaço */
  ownerFilter: { userId: string } | { spaceId: string }
}

/**
 * Gets the full auth context including space awareness.
 * Returns userId, active spaceId (if any), permissions, and ownerFilter for queries.
 */
export async function getAuthContext(): Promise<AuthContext> {
  const userId = await getAuthenticatedUserId()
  const spaceId = await getActiveSpaceId()

  if (!spaceId) {
    return {
      userId,
      spaceId: null,
      permissions: null,
      ownerFilter: { userId },
    }
  }

  const membership = await validateSpaceAccess(userId, spaceId)
  return {
    userId,
    spaceId,
    permissions: new SpacePermissions(membership.role),
    ownerFilter: { spaceId },
  }
}

