    }

    const body = await request.json()
    const { role } = body

    if (!role || !['ADMIN', 'MEMBER', 'LIMITED'].includes(role)) {
      return NextResponse.json({ error: 'Role inválido' }, { status: 400 })
    }

    const updated = await prisma.spaceMember.update({
      where: { id: memberId },
      data: { role },
